import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { registerUser } from '../services/api';

export default function RegisterPage() {
  const [form, setForm] = useState({ name: '', email: '', password: '', department: '', phone: '' });
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await registerUser(form);
      toast.success('Registration successful! Await admin approval.');
      navigate('/login');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Registration failed');
    } finally { setLoading(false); }
  };

  return (
    <div className="min-h-screen bg-darkbg relative overflow-hidden flex items-center justify-center p-4">
      {/* Aesthetic Background Blobs */}
      <div className="absolute top-[-10%] left-[-10%] w-96 h-96 bg-brand-600/30 rounded-full mix-blend-screen filter blur-[100px] animate-blob"></div>
      <div className="absolute top-[20%] right-[-10%] w-96 h-96 bg-accent-500/20 rounded-full mix-blend-screen filter blur-[100px] animate-blob" style={{ animationDelay: '2s' }}></div>
      <div className="absolute -bottom-32 left-[20%] w-96 h-96 bg-brand-400/20 rounded-full mix-blend-screen filter blur-[100px] animate-blob" style={{ animationDelay: '4s' }}></div>

      <div className="w-full max-w-md relative z-10">
        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center w-14 h-14 rounded-2xl bg-gradient-to-tr from-brand-600 to-accent-500 shadow-lg shadow-brand-500/30 mb-4">
            <span className="text-2xl">⚡</span>
          </div>
          <h1 className="font-display font-bold text-white text-3xl tracking-tight text-glow">TaskFlow</h1>
          <p className="text-gray-400 mt-2">Create your employee account</p>
        </div>

        <div className="glass-card rounded-3xl p-8 shadow-2xl shadow-black/50">
          <form onSubmit={handleSubmit} className="space-y-5">
            {[
              { key: 'name', label: 'Full Name', type: 'text', placeholder: 'John Doe' },
              { key: 'email', label: 'Email Address', type: 'email', placeholder: 'you@example.com' },
              { key: 'password', label: 'Password', type: 'password', placeholder: '••••••••' },
              { key: 'department', label: 'Department (optional)', type: 'text', placeholder: 'Engineering' },
              { key: 'phone', label: 'Phone (optional)', type: 'text', placeholder: '+91 XXXXX XXXXX' },
            ].map(field => (
              <div key={field.key}>
                <label className="block text-sm font-medium text-gray-300 mb-1.5">{field.label}</label>
                <input type={field.type} value={form[field.key]} onChange={e => setForm({ ...form, [field.key]: e.target.value })}
                  required={['name','email','password'].includes(field.key)}
                  className="w-full px-5 py-3 glass rounded-xl text-white placeholder-gray-500 focus:outline-none focus:border-brand-400 focus:ring-2 focus:ring-brand-500/50 transition-all"
                  placeholder={field.placeholder} />
              </div>
            ))}
            <button type="submit" disabled={loading}
              className="w-full py-3.5 bg-gradient-to-r from-brand-600 to-accent-500 hover:from-brand-500 hover:to-accent-400 text-white font-semibold rounded-xl shadow-lg shadow-brand-500/25 transition-all transform hover:-translate-y-0.5 disabled:opacity-50 disabled:transform-none mt-6">
              {loading ? 'Registering...' : 'Create Account'}
            </button>
          </form>

          <div className="mt-6 text-center text-sm text-gray-400">
            Already registered? <Link to="/login" className="text-brand-400 hover:text-brand-300 font-semibold transition-colors">Sign in instead</Link>
          </div>
          <p className="mt-4 text-xs text-center text-brand-300/60 font-medium">Your account will be active after admin approval</p>
        </div>
      </div>
    </div>
  );
}
